	const existing = db.prepare(`
    SELECT * FROM teacher_payments WHERE teacher_id = ? AND child_id = ? AND attendance_date = ?
  `).get(teacher_id, child_id, attendance_date);
	const payable = isPaymentEligible(teacher_status, status);
